","request_id":"d839929b-9001-43bb-8e8b-66a9c6f2cc57","structured_request_nodes":[{"id":0,"type":0,"text_node":{"content":"你继续"}},{"id":1,"type":4,"ide_state_node":{"workspaceFolders":[{"repositoryRoot":"/Users/zhukovasky/GolandProjects/xmysql-server","folderRoot":"/Users/zhukovasky/GolandProjects/xmysql-server"}],"workspaceFoldersUnchanged":false}}],"structured_output_nodes":[{"id":1,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_01CQnz2QZjpBGGjvjfsjYNy1","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/DDLOperationsTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\nimport org.junit.jupiter.params.ParameterizedTest;\nimport org.junit.jupiter.params.provider.ValueSource;\n\nimport java.sql.SQLException;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * DDL\u64cd\u4f5c\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5\u6570\u636e\u5e93\u548c\u8868\u7684\u521b\u5efa\u3001\u5220\u9664\u7b49DDL\u64cd\u4f5c\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class DDLOperationsTest extends BaseIntegrationTest {\n \n private static final String TEST_DB_PREFIX = \"test_ddl_db_\";\n private static final String TEST_TABLE_PREFIX = \"test_table_\";\n \n @AfterEach\n public void cleanUp() throws SQLException {\n // \u6e05\u7406\u6d4b\u8bd5\u6570\u636e\u5e93\n for (int i = 1; i <= 5; i++) {\n dropDatabaseIfExists(TEST_DB_PREFIX + i);\n }\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u6570\u636e\u5e93\")\n public void testCreateDatabase() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"1\";\n \n // \u521b\u5efa\u6570\u636e\u5e93\n int result = executeUpdate(\"CREATE DATABASE \" + dbName);\n \n // \u9a8c\u8bc1\u6570\u636e\u5e93\u5df2\u521b\u5efa\n assertThat(databaseExists(dbName)).isTrue();\n printSuccess(\"\u6570\u636e\u5e93 \" + dbName + \" \u521b\u5efa\u6210\u529f\");\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u6570\u636e\u5e93 - IF NOT EXISTS\")\n public void testCreateDatabaseIfNotExists() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"2\";\n \n // \u7b2c\u4e00\u6b21\u521b\u5efa\n executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + dbName);\n assertThat(databaseExists(dbName)).isTrue();\n \n // \u7b2c\u4e8c\u6b21\u521b\u5efa\uff08\u4e0d\u5e94\u8be5\u62a5\u9519\uff09\n assertThatCode(() -> executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + dbName))\n .doesNotThrowAnyException();\n \n printSuccess(\"IF NOT EXISTS \u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u6570\u636e\u5e93 - \u6307\u5b9a\u5b57\u7b26\u96c6\")\n public void testCreateDatabaseWithCharset() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"3\";\n \n // \u521b\u5efa\u5e26\u5b57\u7b26\u96c6\u7684\u6570\u636e\u5e93\n executeUpdate(\"CREATE DATABASE \" + dbName + \" CHARACTER SET utf8mb4\");\n \n assertThat(databaseExists(dbName)).isTrue();\n printSuccess(\"\u5e26\u5b57\u7b26\u96c6\u7684\u6570\u636e\u5e93\u521b\u5efa\u6210\u529f\");\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5\u5220\u9664\u6570\u636e\u5e93\")\n public void testDropDatabase() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"4\";\n \n // \u5148\u521b\u5efa\u6570\u636e\u5e93\n executeUpdate(\"CREATE DATABASE \" + dbName);\n assertThat(databaseExists(dbName)).isTrue();\n \n // \u5220\u9664\u6570\u636e\u5e93\n executeUpdate(\"DROP DATABASE \" + dbName);\n assertThat(databaseExists(dbName)).isFalse();\n \n printSuccess(\"\u6570\u636e\u5e93\u5220\u9664\u6210\u529f\");\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5\u5220\u9664\u6570\u636e\u5e93 - IF EXISTS\")\n public void testDropDatabaseIfExists() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"5\";\n \n // \u5220\u9664\u4e0d\u5b58\u5728\u7684\u6570\u636e\u5e93\uff08\u4e0d\u5e94\u8be5\u62a5\u9519\uff09\n assertThatCode(() -> executeUpdate(\"DROP DATABASE IF EXISTS \" + dbName))\n .doesNotThrowAnyException();\n \n printSuccess(\"DROP IF EXISTS \u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u8868 - \u57fa\u672c\u7c7b\u578b\")\n public void testCreateTableBasicTypes() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"table_test\";\n String tableName = TEST_TABLE_PREFIX + \"basic\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n String createTableSql = \"\"\"\n CREATE TABLE %s (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(100) NOT NULL,\n age INT,\n salary DECIMAL(10,2),\n is_active BOOLEAN DEFAULT TRUE,\n created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n )\n \"\"\".formatted(tableName);\n \n executeUpdate(createTableSql);\n assertThat(tableExists(tableName)).isTrue();\n \n printSuccess(\"\u57fa\u672c\u7c7b\u578b\u8868\u521b\u5efa\u6210\u529f\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u8868 - \u5e26\u7d22\u5f15\")\n public void testCreateTableWithIndex() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"index_test\";\n String tableName = TEST_TABLE_PREFIX + \"indexed\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n String createTableSql = \"\"\"\n CREATE TABLE %s (\n id INT PRIMARY KEY AUTO_INCREMENT,\n email VARCHAR(100) UNIQUE NOT NULL,\n username VARCHAR(50) NOT NULL,\n INDEX idx_username (username)\n )\n \"\"\".formatted(tableName);\n \n executeUpdate(createTableSql);\n assertThat(tableExists(tableName)).isTrue();\n \n printSuccess(\"\u5e26\u7d22\u5f15\u7684\u8868\u521b\u5efa\u6210\u529f\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5\u521b\u5efa\u8868 - \u5916\u952e\u7ea6\u675f\")\n public void testCreateTableWithForeignKey() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"fk_test\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n // \u521b\u5efa\u7236\u8868\n executeUpdate(\"\"\"\n CREATE TABLE users (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(100) NOT NULL\n )\n \"\"\");\n \n // \u521b\u5efa\u5b50\u8868\uff08\u5e26\u5916\u952e\uff09\n executeUpdate(\"\"\"\n CREATE TABLE orders (\n id INT PRIMARY KEY AUTO_INCREMENT,\n user_id INT,\n amount DECIMAL(10,2),\n FOREIGN KEY (user_id) REFERENCES users(id)\n )\n \"\"\");\n \n assertThat(tableExists(\"users\")).isTrue();\n assertThat(tableExists(\"orders\")).isTrue();\n \n printSuccess(\"\u5e26\u5916\u952e\u7684\u8868\u521b\u5efa\u6210\u529f\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @Test\n @Order(9)\n @DisplayName(\"\u6d4b\u8bd5\u5220\u9664\u8868\")\n public void testDropTable() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"drop_test\";\n String tableName = TEST_TABLE_PREFIX + \"drop\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n // \u521b\u5efa\u8868\n executeUpdate(\"CREATE TABLE \" + tableName + \" (id INT PRIMARY KEY)\");\n assertThat(tableExists(tableName)).isTrue();\n \n // \u5220\u9664\u8868\n executeUpdate(\"DROP TABLE \" + tableName);\n assertThat(tableExists(tableName)).isFalse();\n \n printSuccess(\"\u8868\u5220\u9664\u6210\u529f\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @ParameterizedTest\n @ValueSource(strings = {\"utf8\", \"utf8mb4\", \"latin1\"})\n @DisplayName(\"\u6d4b\u8bd5\u4e0d\u540c\u5b57\u7b26\u96c6\u7684\u6570\u636e\u5e93\u521b\u5efa\")\n public void testCreateDatabaseWithDifferentCharsets(String charset) throws SQLException {\n String dbName = TEST_DB_PREFIX + \"charset_\" + charset;\n \n executeUpdate(\"CREATE DATABASE \" + dbName + \" CHARACTER SET \" + charset);\n assertThat(databaseExists(dbName)).isTrue();\n \n printSuccess(\"\u5b57\u7b26\u96c6 \" + charset + \" \u7684\u6570\u636e\u5e93\u521b\u5efa\u6210\u529f\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @Test\n @Order(10)\n @DisplayName(\"\u6d4b\u8bd5ALTER TABLE - \u6dfb\u52a0\u5217\")\n public void testAlterTableAddColumn() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"alter_test\";\n String tableName = TEST_TABLE_PREFIX + \"alter\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n // \u521b\u5efa\u8868\n executeUpdate(\"CREATE TABLE \" + tableName + \" (id INT PRIMARY KEY)\");\n \n // \u6dfb\u52a0\u5217\n executeUpdate(\"ALTER TABLE \" + tableName + \" ADD COLUMN name VARCHAR(100)\");\n executeUpdate(\"ALTER TABLE \" + tableName + \" ADD COLUMN age INT DEFAULT 0\");\n \n printSuccess(\"ALTER TABLE ADD COLUMN \u6d4b\u8bd5\u901a\u8fc7\");\n \n dropDatabaseIfExists(dbName);\n }\n \n @Test\n @Order(11)\n @DisplayName(\"\u6d4b\u8bd5TRUNCATE TABLE\")\n public void testTruncateTable() throws SQLException {\n String dbName = TEST_DB_PREFIX + \"truncate_test\";\n String tableName = TEST_TABLE_PREFIX + \"truncate\";\n \n createTestDatabase(dbName);\n useDatabase(dbName);\n \n // \u521b\u5efa\u8868\u5e76\u63d2\u5165\u6570\u636e\n executeUpdate(\"CREATE TABLE \" + tableName + \" (id INT PRIMARY KEY, name VARCHAR(50))\");\n executeUpdate(\"INSERT INTO \" + tableName + \" VALUES (1, 'test1'), (2, 'test2')\");\n \n assertThat(getTableRowCount(tableName)).isEqualTo(2);\n \n // \u6e05\u7a7a\u8868\n executeUpdate(\"TRUNCATE TABLE \" + tableName);\n assertThat(getTableRowCount(tableName)).isEqualTo(0);\n \n printSuccess(\"TRUNCATE TABLE \u6d4b\u8bd5\u901a\u8fc7\");\n \n dropDatabaseIfExists(dbName);\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":2,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_012k48jtLJwh1kV1inBZPLzE","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/DMLOperationsTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\n\nimport java.sql.PreparedStatement;\nimport java.sql.ResultSet;\nimport java.sql.SQLException;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * DML\u64cd\u4f5c\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5INSERT, UPDATE, DELETE\u7b49\u6570\u636e\u64cd\u4f5c\u8bed\u53e5\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class DMLOperationsTest extends BaseIntegrationTest {\n \n private static final String TEST_DB = \"test_dml_operations\";\n private static final String USERS_TABLE = \"users\";\n private static final String PRODUCTS_TABLE = \"products\";\n \n @BeforeAll\n public static void setUpTestDatabase() throws SQLException {\n // \u521b\u5efa\u6d4b\u8bd5\u6570\u636e\u5e93\n connection.createStatement().executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + TEST_DB);\n connection.createStatement().executeUpdate(\"USE \" + TEST_DB);\n \n // \u521b\u5efa\u7528\u6237\u8868\n connection.createStatement().executeUpdate(\"\"\"\n CREATE TABLE IF NOT EXISTS users (\n id INT PRIMARY KEY AUTO_INCREMENT,\n username VARCHAR(50) NOT NULL UNIQUE,\n email VARCHAR(100) NOT NULL,\n age INT DEFAULT 18,\n created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n )\n \"\"\");\n \n // \u521b\u5efa\u4ea7\u54c1\u8868\n connection.createStatement().executeUpdate(\"\"\"\n CREATE TABLE IF NOT EXISTS products (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(100) NOT NULL,\n price DECIMAL(10,2) NOT NULL,\n stock INT DEFAULT 0,\n category VARCHAR(50)\n )\n \"\"\");\n }\n \n @AfterAll\n public static void cleanUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"DROP DATABASE IF EXISTS \" + TEST_DB);\n }\n \n @BeforeEach\n public void clearTables() throws SQLException {\n executeUpdate(\"TRUNCATE TABLE \" + USERS_TABLE);\n executeUpdate(\"TRUNCATE TABLE \" + PRODUCTS_TABLE);\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5INSERT - \u5355\u884c\u63d2\u5165\")\n public void testInsertSingleRow() throws SQLException {\n String sql = \"INSERT INTO users (username, email, age) VALUES ('alice', 'alice@example.com', 25)\";\n int rowsAffected = executeUpdate(sql);\n \n assertThat(rowsAffected).isEqualTo(1);\n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(1);\n \n printSuccess(\"\u5355\u884c\u63d2\u5165\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5INSERT - \u6279\u91cf\u63d2\u5165\")\n public void testInsertMultipleRows() throws SQLException {\n String sql = \"\"\"\n INSERT INTO users (username, email, age) VALUES \n ('bob', 'bob@example.com', 30),\n ('charlie', 'charlie@example.com', 28),\n ('diana', 'diana@example.com', 32)\n \"\"\";\n \n int rowsAffected = executeUpdate(sql);\n \n assertThat(rowsAffected).isEqualTo(3);\n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(3);\n \n printSuccess(\"\u6279\u91cf\u63d2\u5165\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5INSERT - PreparedStatement\")\n public void testInsertWithPreparedStatement() throws SQLException {\n String sql = \"INSERT INTO users (username, email, age) VALUES (?, ?, ?)\";\n \n try (PreparedStatement pstmt = connection.prepareStatement(sql)) {\n // \u63d2\u5165\u7b2c\u4e00\u6761\n pstmt.setString(1, \"eve\");\n pstmt.setString(2, \"eve@example.com\");\n pstmt.setInt(3, 24);\n int rows1 = pstmt.executeUpdate();\n \n // \u63d2\u5165\u7b2c\u4e8c\u6761\n pstmt.setString(1, \"frank\");\n pstmt.setString(2, \"frank@example.com\");\n pstmt.setInt(3, 35);\n int rows2 = pstmt.executeUpdate();\n \n assertThat(rows1).isEqualTo(1);\n assertThat(rows2).isEqualTo(1);\n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(2);\n }\n \n printSuccess(\"PreparedStatement\u63d2\u5165\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5INSERT - \u9ed8\u8ba4\u503c\")\n public void testInsertWithDefaultValues() throws SQLException {\n String sql = \"INSERT INTO users (username, email) VALUES ('grace', 'grace@example.com')\";\n executeUpdate(sql);\n \n // \u9a8c\u8bc1\u9ed8\u8ba4\u503c\n try (ResultSet rs = executeQuery(\"SELECT age FROM users WHERE username = 'grace'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"age\")).isEqualTo(18); // \u9ed8\u8ba4\u503c\n }\n \n printSuccess(\"\u9ed8\u8ba4\u503c\u63d2\u5165\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5UPDATE - \u5355\u884c\u66f4\u65b0\")\n public void testUpdateSingleRow() throws SQLException {\n // \u5148\u63d2\u5165\u6570\u636e\n executeUpdate(\"INSERT INTO users (username, email, age) VALUES ('henry', 'henry@example.com', 25)\");\n \n // \u66f4\u65b0\u6570\u636e\n String updateSql = \"UPDATE users SET age = 26 WHERE username = 'henry'\";\n int rowsAffected = executeUpdate(updateSql);\n \n assertThat(rowsAffected).isEqualTo(1);\n \n // \u9a8c\u8bc1\u66f4\u65b0\u7ed3\u679c\n try (ResultSet rs = executeQuery(\"SELECT age FROM users WHERE username = 'henry'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"age\")).isEqualTo(26);\n }\n \n printSuccess(\"\u5355\u884c\u66f4\u65b0\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5UPDATE - \u6279\u91cf\u66f4\u65b0\")\n public void testUpdateMultipleRows() throws SQLException {\n // \u63d2\u5165\u6d4b\u8bd5\u6570\u636e\n executeUpdate(\"\"\"\n INSERT INTO users (username, email, age) VALUES \n ('user1', 'user1@example.com', 20),\n ('user2', 'user2@example.com', 21),\n ('user3', 'user3@example.com', 22)\n \"\"\");\n \n // \u6279\u91cf\u66f4\u65b0\n String updateSql = \"UPDATE users SET age = age + 1 WHERE age < 25\";\n int rowsAffected = executeUpdate(updateSql);\n \n assertThat(rowsAffected).isEqualTo(3);\n \n printSuccess(\"\u6279\u91cf\u66f4\u65b0\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5UPDATE - PreparedStatement\")\n public void testUpdateWithPreparedStatement() throws SQLException {\n executeUpdate(\"INSERT INTO users (username, email, age) VALUES ('iris', 'iris@example.com', 25)\");\n \n String sql = \"UPDATE users SET email = ?, age = ? WHERE username = ?\";\n try (PreparedStatement pstmt = connection.prepareStatement(sql)) {\n pstmt.setString(1, \"newemail@example.com\");\n pstmt.setInt(2, 30);\n pstmt.setString(3, \"iris\");\n \n int rowsAffected = pstmt.executeUpdate();\n assertThat(rowsAffected).isEqualTo(1);\n }\n \n printSuccess(\"PreparedStatement\u66f4\u65b0\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5DELETE - \u5355\u884c\u5220\u9664\")\n public void testDeleteSingleRow() throws SQLException {\n executeUpdate(\"INSERT INTO users (username, email, age) VALUES ('jack', 'jack@example.com', 25)\");\n \n String deleteSql = \"DELETE FROM users WHERE username = 'jack'\";\n int rowsAffected = executeUpdate(deleteSql);\n \n assertThat(rowsAffected).isEqualTo(1);\n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(0);\n \n printSuccess(\"\u5355\u884c\u5220\u9664\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(9)\n @DisplayName(\"\u6d4b\u8bd5DELETE - \u6279\u91cf\u5220\u9664\")\n public void testDeleteMultipleRows() throws SQLException {\n executeUpdate(\"\"\"\n INSERT INTO users (username, email, age) VALUES \n ('user1', 'user1@example.com', 20),\n ('user2', 'user2@example.com', 25),\n ('user3', 'user3@example.com', 30)\n \"\"\");\n \n String deleteSql = \"DELETE FROM users WHERE age >= 25\";\n int rowsAffected = executeUpdate(deleteSql);\n \n assertThat(rowsAffected).isEqualTo(2);\n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(1);\n \n printSuccess(\"\u6279\u91cf\u5220\u9664\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(10)\n @DisplayName(\"\u6d4b\u8bd5DELETE - \u5168\u90e8\u5220\u9664\")\n public void testDeleteAll() throws SQLException {\n executeUpdate(\"\"\"\n INSERT INTO users (username, email, age) VALUES \n ('user1', 'user1@example.com', 20),\n ('user2', 'user2@example.com', 25)\n \"\"\");\n \n String deleteSql = \"DELETE FROM users\";\n executeUpdate(deleteSql);\n \n assertThat(getTableRowCount(USERS_TABLE)).isEqualTo(0);\n \n printSuccess(\"\u5168\u90e8\u5220\u9664\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(11)\n @DisplayName(\"\u6d4b\u8bd5INSERT - \u4ea7\u54c1\u6570\u636e\uff08DECIMAL\u7c7b\u578b\uff09\")\n public void testInsertProductsWithDecimal() throws SQLException {\n String sql = \"\"\"\n INSERT INTO products (name, price, stock, category) VALUES \n ('Laptop', 999.99, 10, 'Electronics'),\n ('Mouse', 29.99, 50, 'Electronics'),\n ('Desk', 299.50, 5, 'Furniture')\n \"\"\";\n \n int rowsAffected = executeUpdate(sql);\n assertThat(rowsAffected).isEqualTo(3);\n \n // \u9a8c\u8bc1DECIMAL\u7cbe\u5ea6\n try (ResultSet rs = executeQuery(\"SELECT price FROM products WHERE name = 'Laptop'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBigDecimal(\"price\").doubleValue()).isEqualTo(999.99);\n }\n \n printSuccess(\"DECIMAL\u7c7b\u578b\u63d2\u5165\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(12)\n @DisplayName(\"\u6d4b\u8bd5UPDATE - \u5e93\u5b58\u66f4\u65b0\")\n public void testUpdateProductStock() throws SQLException {\n executeUpdate(\"INSERT INTO products (name, price, stock) VALUES ('Widget', 19.99, 100)\");\n \n // \u51cf\u5c11\u5e93\u5b58\n executeUpdate(\"UPDATE products SET stock = stock - 10 WHERE name = 'Widget'\");\n \n try (ResultSet rs = executeQuery(\"SELECT stock FROM products WHERE name = 'Widget'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"stock\")).isEqualTo(90);\n }\n \n printSuccess(\"\u5e93\u5b58\u66f4\u65b0\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(13)\n @DisplayName(\"\u6d4b\u8bd5INSERT - UNIQUE\u7ea6\u675f\u8fdd\u53cd\")\n public void testInsertUniqueConstraintViolation() throws SQLException {\n executeUpdate(\"INSERT INTO users (username, email, age) VALUES ('unique_user', 'unique@example.com', 25)\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684username\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO users (username, email, age) VALUES ('unique_user', 'another@example.com', 30)\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"UNIQUE\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":3,"type":0,"content":"好的！我继续创建更多的测试类。让我为各个功能模块创建完整的 JUnit 测试：
