","request_id":"1a637926-2e25-4724-bf8e-f6abf60fbf73","structured_request_nodes":[{"id":1,"type":1,"tool_result_node":{"content":"File saved. Saved file {jdbc_client/src/test/java/com/xmysql/server/test/DDLOperationsTest.java}","is_error":false,"request_id":"d839929b-9001-43bb-8e8b-66a9c6f2cc57","tool_use_id":"toolu_vrtx_01CQnz2QZjpBGGjvjfsjYNy1"}},{"id":2,"type":1,"tool_result_node":{"content":"File saved. Saved file {jdbc_client/src/test/java/com/xmysql/server/test/DMLOperationsTest.java}","is_error":false,"request_id":"d839929b-9001-43bb-8e8b-66a9c6f2cc57","tool_use_id":"toolu_vrtx_012k48jtLJwh1kV1inBZPLzE"}},{"id":3,"type":4,"ide_state_node":{"workspaceFolders":[{"repositoryRoot":"/Users/zhukovasky/GolandProjects/xmysql-server","folderRoot":"/Users/zhukovasky/GolandProjects/xmysql-server"}],"workspaceFoldersUnchanged":false}}],"structured_output_nodes":[{"id":1,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_01LtBwQXb5zi8yH2AGS5ENL2","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/SelectQueryTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\n\nimport java.sql.ResultSet;\nimport java.sql.SQLException;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * SELECT\u67e5\u8be2\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5\u5404\u79cdSELECT\u67e5\u8be2\u8bed\u53e5\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class SelectQueryTest extends BaseIntegrationTest {\n \n private static final String TEST_DB = \"test_select_queries\";\n \n @BeforeAll\n public static void setUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + TEST_DB);\n connection.createStatement().executeUpdate(\"USE \" + TEST_DB);\n \n // \u521b\u5efa\u5458\u5de5\u8868\n connection.createStatement().executeUpdate(\"\"\"\n CREATE TABLE employees (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(100) NOT NULL,\n department VARCHAR(50),\n salary DECIMAL(10,2),\n hire_date DATE,\n age INT\n )\n \"\"\");\n \n // \u63d2\u5165\u6d4b\u8bd5\u6570\u636e\n connection.createStatement().executeUpdate(\"\"\"\n INSERT INTO employees (name, department, salary, hire_date, age) VALUES\n ('Alice', 'Engineering', 80000.00, '2020-01-15', 28),\n ('Bob', 'Sales', 60000.00, '2019-03-20', 32),\n ('Charlie', 'Engineering', 90000.00, '2018-06-10', 35),\n ('Diana', 'HR', 55000.00, '2021-02-01', 26),\n ('Eve', 'Sales', 65000.00, '2020-08-15', 29),\n ('Frank', 'Engineering', 95000.00, '2017-11-05', 40),\n ('Grace', 'HR', 58000.00, '2022-01-10', 24)\n \"\"\");\n }\n \n @AfterAll\n public static void cleanUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"DROP DATABASE IF EXISTS \" + TEST_DB);\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5SELECT - \u67e5\u8be2\u6240\u6709\u5217\")\n public void testSelectAllColumns() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT * FROM employees\")) {\n int count = 0;\n while (rs.next()) {\n count++;\n assertThat(rs.getString(\"name\")).isNotNull();\n }\n assertThat(count).isEqualTo(7);\n }\n \n printSuccess(\"\u67e5\u8be2\u6240\u6709\u5217\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5SELECT - \u67e5\u8be2\u6307\u5b9a\u5217\")\n public void testSelectSpecificColumns() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT name, department FROM employees\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"name\")).isNotNull();\n assertThat(rs.getString(\"department\")).isNotNull();\n \n // \u9a8c\u8bc1\u53ea\u6709\u8fd9\u4e24\u5217\n assertThat(rs.getMetaData().getColumnCount()).isEqualTo(2);\n }\n \n printSuccess(\"\u67e5\u8be2\u6307\u5b9a\u5217\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5SELECT - WHERE\u6761\u4ef6\")\n public void testSelectWithWhere() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT * FROM employees WHERE department = 'Engineering'\")) {\n int count = 0;\n while (rs.next()) {\n count++;\n assertThat(rs.getString(\"department\")).isEqualTo(\"Engineering\");\n }\n assertThat(count).isEqualTo(3);\n }\n \n printSuccess(\"WHERE\u6761\u4ef6\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5SELECT - \u591a\u4e2aWHERE\u6761\u4ef6\uff08AND\uff09\")\n public void testSelectWithMultipleWhereAnd() throws SQLException {\n String sql = \"SELECT * FROM employees WHERE department = 'Engineering' AND salary > 85000\";\n \n try (ResultSet rs = executeQuery(sql)) {\n int count = 0;\n while (rs.next()) {\n count++;\n assertThat(rs.getString(\"department\")).isEqualTo(\"Engineering\");\n assertThat(rs.getBigDecimal(\"salary\").doubleValue()).isGreaterThan(85000);\n }\n assertThat(count).isEqualTo(2); // Charlie and Frank\n }\n \n printSuccess(\"\u591a\u4e2aAND\u6761\u4ef6\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5SELECT - \u591a\u4e2aWHERE\u6761\u4ef6\uff08OR\uff09\")\n public void testSelectWithMultipleWhereOr() throws SQLException {\n String sql = \"SELECT * FROM employees WHERE department = 'HR' OR department = 'Sales'\";\n \n try (ResultSet rs = executeQuery(sql)) {\n int count = 0;\n while (rs.next()) {\n count++;\n String dept = rs.getString(\"department\");\n assertThat(dept).isIn(\"HR\", \"Sales\");\n }\n assertThat(count).isEqualTo(4); // Bob, Diana, Eve, Grace\n }\n \n printSuccess(\"\u591a\u4e2aOR\u6761\u4ef6\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5SELECT - ORDER BY\u5347\u5e8f\")\n public void testSelectOrderByAsc() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT name, salary FROM employees ORDER BY salary ASC\")) {\n double previousSalary = 0;\n while (rs.next()) {\n double currentSalary = rs.getBigDecimal(\"salary\").doubleValue();\n assertThat(currentSalary).isGreaterThanOrEqualTo(previousSalary);\n previousSalary = currentSalary;\n }\n }\n \n printSuccess(\"ORDER BY ASC\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5SELECT - ORDER BY\u964d\u5e8f\")\n public void testSelectOrderByDesc() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT name, salary FROM employees ORDER BY salary DESC\")) {\n double previousSalary = Double.MAX_VALUE;\n while (rs.next()) {\n double currentSalary = rs.getBigDecimal(\"salary\").doubleValue();\n assertThat(currentSalary).isLessThanOrEqualTo(previousSalary);\n previousSalary = currentSalary;\n }\n }\n \n printSuccess(\"ORDER BY DESC\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5SELECT - LIMIT\")\n public void testSelectWithLimit() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT * FROM employees LIMIT 3\")) {\n int count = 0;\n while (rs.next()) {\n count++;\n }\n assertThat(count).isEqualTo(3);\n }\n \n printSuccess(\"LIMIT\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(9)\n @DisplayName(\"\u6d4b\u8bd5SELECT - LIMIT with OFFSET\")\n public void testSelectWithLimitOffset() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT * FROM employees LIMIT 2 OFFSET 3\")) {\n int count = 0;\n while (rs.next()) {\n count++;\n }\n assertThat(count).isEqualTo(2);\n }\n \n printSuccess(\"LIMIT OFFSET\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(10)\n @DisplayName(\"\u6d4b\u8bd5SELECT - COUNT\u805a\u5408\u51fd\u6570\")\n public void testSelectCount() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT COUNT(*) as total FROM employees\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"total\")).isEqualTo(7);\n }\n \n printSuccess(\"COUNT\u805a\u5408\u51fd\u6570\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(11)\n @DisplayName(\"\u6d4b\u8bd5SELECT - SUM\u805a\u5408\u51fd\u6570\")\n public void testSelectSum() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT SUM(salary) as total_salary FROM employees\")) {\n assertThat(rs.next()).isTrue();\n double totalSalary = rs.getBigDecimal(\"total_salary\").doubleValue();\n assertThat(totalSalary).isGreaterThan(0);\n }\n \n printSuccess(\"SUM\u805a\u5408\u51fd\u6570\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(12)\n @DisplayName(\"\u6d4b\u8bd5SELECT - AVG\u805a\u5408\u51fd\u6570\")\n public void testSelectAvg() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT AVG(salary) as avg_salary FROM employees\")) {\n assertThat(rs.next()).isTrue();\n double avgSalary = rs.getBigDecimal(\"avg_salary\").doubleValue();\n assertThat(avgSalary).isBetween(60000.0, 80000.0);\n }\n \n printSuccess(\"AVG\u805a\u5408\u51fd\u6570\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(13)\n @DisplayName(\"\u6d4b\u8bd5SELECT - MAX\u548cMIN\u805a\u5408\u51fd\u6570\")\n public void testSelectMaxMin() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT MAX(salary) as max_sal, MIN(salary) as min_sal FROM employees\")) {\n assertThat(rs.next()).isTrue();\n double maxSalary = rs.getBigDecimal(\"max_sal\").doubleValue();\n double minSalary = rs.getBigDecimal(\"min_sal\").doubleValue();\n \n assertThat(maxSalary).isEqualTo(95000.00);\n assertThat(minSalary).isEqualTo(55000.00);\n }\n \n printSuccess(\"MAX/MIN\u805a\u5408\u51fd\u6570\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(14)\n @DisplayName(\"\u6d4b\u8bd5SELECT - GROUP BY\")\n public void testSelectGroupBy() throws SQLException {\n String sql = \"SELECT department, COUNT(*) as emp_count FROM employees GROUP BY department\";\n \n try (ResultSet rs = executeQuery(sql)) {\n int groupCount = 0;\n while (rs.next()) {\n groupCount++;\n String dept = rs.getString(\"department\");\n int count = rs.getInt(\"emp_count\");\n \n if (\"Engineering\".equals(dept)) {\n assertThat(count).isEqualTo(3);\n } else if (\"Sales\".equals(dept)) {\n assertThat(count).isEqualTo(2);\n } else if (\"HR\".equals(dept)) {\n assertThat(count).isEqualTo(2);\n }\n }\n assertThat(groupCount).isEqualTo(3);\n }\n \n printSuccess(\"GROUP BY\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(15)\n @DisplayName(\"\u6d4b\u8bd5SELECT - GROUP BY with HAVING\")\n public void testSelectGroupByHaving() throws SQLException {\n String sql = \"SELECT department, AVG(salary) as avg_sal FROM employees GROUP BY department HAVING AVG(salary) > 60000\";\n \n try (ResultSet rs = executeQuery(sql)) {\n while (rs.next()) {\n double avgSal = rs.getBigDecimal(\"avg_sal\").doubleValue();\n assertThat(avgSal).isGreaterThan(60000);\n }\n }\n \n printSuccess(\"GROUP BY HAVING\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(16)\n @DisplayName(\"\u6d4b\u8bd5SELECT - DISTINCT\")\n public void testSelectDistinct() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT DISTINCT department FROM employees\")) {\n int count = 0;\n while (rs.next()) {\n count++;\n }\n assertThat(count).isEqualTo(3); // Engineering, Sales, HR\n }\n \n printSuccess(\"DISTINCT\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(17)\n @DisplayName(\"\u6d4b\u8bd5SELECT - LIKE\u6a21\u7cca\u67e5\u8be2\")\n public void testSelectLike() throws SQLException {\n try (ResultSet rs = executeQuery(\"SELECT * FROM employees WHERE name LIKE 'A%'\")) {\n while (rs.next()) {\n String name = rs.getString(\"name\");\n assertThat(name).startsWith(\"A\");\n }\n }\n \n printSuccess(\"LIKE\u6a21\u7cca\u67e5\u8be2\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(18)\n @DisplayName(\"\u6d4b\u8bd5SELECT - IN\u6761\u4ef6\")\n public void testSelectIn() throws SQLException {\n String sql = \"SELECT * FROM employees WHERE department IN ('Engineering', 'HR')\";\n \n try (ResultSet rs = executeQuery(sql)) {\n int count = 0;\n while (rs.next()) {\n count++;\n String dept = rs.getString(\"department\");\n assertThat(dept).isIn(\"Engineering\", \"HR\");\n }\n assertThat(count).isEqualTo(5);\n }\n \n printSuccess(\"IN\u6761\u4ef6\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(19)\n @DisplayName(\"\u6d4b\u8bd5SELECT - BETWEEN\u6761\u4ef6\")\n public void testSelectBetween() throws SQLException {\n String sql = \"SELECT * FROM employees WHERE salary BETWEEN 60000 AND 80000\";\n \n try (ResultSet rs = executeQuery(sql)) {\n while (rs.next()) {\n double salary = rs.getBigDecimal(\"salary\").doubleValue();\n assertThat(salary).isBetween(60000.0, 80000.0);\n }\n }\n \n printSuccess(\"BETWEEN\u6761\u4ef6\u6d4b\u8bd5\u901a\u8fc7\");\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":2,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_01UM7pv9BHqVe9fRhGauoMr6","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/TransactionTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\n\nimport java.sql.ResultSet;\nimport java.sql.SQLException;\nimport java.sql.Savepoint;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * \u4e8b\u52a1\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5\u4e8b\u52a1\u7684COMMIT\u3001ROLLBACK\u3001SAVEPOINT\u7b49\u529f\u80fd\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class TransactionTest extends BaseIntegrationTest {\n \n private static final String TEST_DB = \"test_transactions\";\n private static final String ACCOUNTS_TABLE = \"accounts\";\n \n @BeforeAll\n public static void setUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + TEST_DB);\n connection.createStatement().executeUpdate(\"USE \" + TEST_DB);\n \n // \u521b\u5efa\u8d26\u6237\u8868\n connection.createStatement().executeUpdate(\"\"\"\n CREATE TABLE accounts (\n id INT PRIMARY KEY AUTO_INCREMENT,\n account_name VARCHAR(100) NOT NULL,\n balance DECIMAL(10,2) NOT NULL DEFAULT 0.00\n )\n \"\"\");\n }\n \n @AfterAll\n public static void cleanUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"DROP DATABASE IF EXISTS \" + TEST_DB);\n }\n \n @BeforeEach\n public void clearTable() throws SQLException {\n executeUpdate(\"TRUNCATE TABLE \" + ACCOUNTS_TABLE);\n // \u786e\u4fdd\u81ea\u52a8\u63d0\u4ea4\u662f\u5f00\u542f\u7684\n connection.setAutoCommit(true);\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5\u4e8b\u52a1COMMIT\")\n public void testTransactionCommit() throws SQLException {\n // \u5173\u95ed\u81ea\u52a8\u63d0\u4ea4\n connection.setAutoCommit(false);\n \n try {\n // \u63d2\u5165\u6570\u636e\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Alice', 1000.00)\");\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Bob', 2000.00)\");\n \n // \u63d0\u4ea4\u4e8b\u52a1\n connection.commit();\n \n // \u9a8c\u8bc1\u6570\u636e\u5df2\u4fdd\u5b58\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(2);\n \n printSuccess(\"\u4e8b\u52a1COMMIT\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5\u4e8b\u52a1ROLLBACK\")\n public void testTransactionRollback() throws SQLException {\n connection.setAutoCommit(false);\n \n try {\n // \u63d2\u5165\u6570\u636e\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Charlie', 3000.00)\");\n \n // \u9a8c\u8bc1\u6570\u636e\u5728\u4e8b\u52a1\u4e2d\u5b58\u5728\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(1);\n \n // \u56de\u6eda\u4e8b\u52a1\n connection.rollback();\n \n // \u9a8c\u8bc1\u6570\u636e\u5df2\u56de\u6eda\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(0);\n \n printSuccess(\"\u4e8b\u52a1ROLLBACK\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5\u8f6c\u8d26\u4e8b\u52a1 - \u6210\u529f\u573a\u666f\")\n public void testTransferMoneySuccess() throws SQLException {\n // \u521d\u59cb\u5316\u8d26\u6237\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Alice', 1000.00)\");\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Bob', 500.00)\");\n \n connection.setAutoCommit(false);\n \n try {\n // \u4eceAlice\u8f6c\u8d26200\u7ed9Bob\n executeUpdate(\"UPDATE accounts SET balance = balance - 200 WHERE account_name = 'Alice'\");\n executeUpdate(\"UPDATE accounts SET balance = balance + 200 WHERE account_name = 'Bob'\");\n \n // \u63d0\u4ea4\u4e8b\u52a1\n connection.commit();\n \n // \u9a8c\u8bc1\u4f59\u989d\n try (ResultSet rs = executeQuery(\"SELECT balance FROM accounts WHERE account_name = 'Alice'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBigDecimal(\"balance\").doubleValue()).isEqualTo(800.00);\n }\n \n try (ResultSet rs = executeQuery(\"SELECT balance FROM accounts WHERE account_name = 'Bob'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBigDecimal(\"balance\").doubleValue()).isEqualTo(700.00);\n }\n \n printSuccess(\"\u8f6c\u8d26\u4e8b\u52a1\u6210\u529f\u573a\u666f\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5\u8f6c\u8d26\u4e8b\u52a1 - \u5931\u8d25\u56de\u6eda\u573a\u666f\")\n public void testTransferMoneyFailureRollback() throws SQLException {\n // \u521d\u59cb\u5316\u8d26\u6237\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Alice', 100.00)\");\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Bob', 500.00)\");\n \n connection.setAutoCommit(false);\n \n try {\n // \u5c1d\u8bd5\u4eceAlice\u8f6c\u8d26200\u7ed9Bob\uff08\u4f59\u989d\u4e0d\u8db3\uff09\n executeUpdate(\"UPDATE accounts SET balance = balance - 200 WHERE account_name = 'Alice'\");\n \n // \u68c0\u67e5\u4f59\u989d\u662f\u5426\u4e3a\u8d1f\n try (ResultSet rs = executeQuery(\"SELECT balance FROM accounts WHERE account_name = 'Alice'\")) {\n rs.next();\n double balance = rs.getBigDecimal(\"balance\").doubleValue();\n \n if (balance < 0) {\n // \u4f59\u989d\u4e0d\u8db3\uff0c\u56de\u6eda\u4e8b\u52a1\n connection.rollback();\n printTestInfo(\"\u68c0\u6d4b\u5230\u4f59\u989d\u4e0d\u8db3\uff0c\u4e8b\u52a1\u5df2\u56de\u6eda\");\n } else {\n executeUpdate(\"UPDATE accounts SET balance = balance + 200 WHERE account_name = 'Bob'\");\n connection.commit();\n }\n }\n \n // \u9a8c\u8bc1Alice\u7684\u4f59\u989d\u672a\u6539\u53d8\n try (ResultSet rs = executeQuery(\"SELECT balance FROM accounts WHERE account_name = 'Alice'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBigDecimal(\"balance\").doubleValue()).isEqualTo(100.00);\n }\n \n printSuccess(\"\u8f6c\u8d26\u5931\u8d25\u56de\u6eda\u573a\u666f\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5SAVEPOINT - \u90e8\u5206\u56de\u6eda\")\n public void testSavepoint() throws SQLException {\n connection.setAutoCommit(false);\n \n try {\n // \u63d2\u5165\u7b2c\u4e00\u6761\u8bb0\u5f55\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Alice', 1000.00)\");\n \n // \u521b\u5efa\u4fdd\u5b58\u70b9\n Savepoint savepoint1 = connection.setSavepoint(\"savepoint1\");\n \n // \u63d2\u5165\u7b2c\u4e8c\u6761\u8bb0\u5f55\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Bob', 2000.00)\");\n \n // \u56de\u6eda\u5230\u4fdd\u5b58\u70b9\n connection.rollback(savepoint1);\n \n // \u63d2\u5165\u7b2c\u4e09\u6761\u8bb0\u5f55\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Charlie', 3000.00)\");\n \n // \u63d0\u4ea4\u4e8b\u52a1\n connection.commit();\n \n // \u9a8c\u8bc1\u7ed3\u679c\uff1a\u5e94\u8be5\u6709Alice\u548cCharlie\uff0c\u6ca1\u6709Bob\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(2);\n \n try (ResultSet rs = executeQuery(\"SELECT account_name FROM accounts ORDER BY account_name\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"account_name\")).isEqualTo(\"Alice\");\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"account_name\")).isEqualTo(\"Charlie\");\n }\n \n printSuccess(\"SAVEPOINT\u90e8\u5206\u56de\u6eda\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5\u591a\u4e2aSAVEPOINT\")\n public void testMultipleSavepoints() throws SQLException {\n connection.setAutoCommit(false);\n \n try {\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Account1', 100.00)\");\n Savepoint sp1 = connection.setSavepoint(\"sp1\");\n \n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Account2', 200.00)\");\n Savepoint sp2 = connection.setSavepoint(\"sp2\");\n \n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Account3', 300.00)\");\n Savepoint sp3 = connection.setSavepoint(\"sp3\");\n \n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('Account4', 400.00)\");\n \n // \u56de\u6eda\u5230sp2\n connection.rollback(sp2);\n \n // \u63d0\u4ea4\n connection.commit();\n \n // \u5e94\u8be5\u53ea\u6709Account1\u548cAccount2\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(2);\n \n printSuccess(\"\u591a\u4e2aSAVEPOINT\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5\u4e8b\u52a1\u9694\u79bb - READ COMMITTED\")\n public void testTransactionIsolationReadCommitted() throws SQLException {\n // \u8bbe\u7f6e\u9694\u79bb\u7ea7\u522b\n connection.setTransactionIsolation(java.sql.Connection.TRANSACTION_READ_COMMITTED);\n \n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('TestAccount', 1000.00)\");\n \n connection.setAutoCommit(false);\n \n try {\n executeUpdate(\"UPDATE accounts SET balance = 1500.00 WHERE account_name = 'TestAccount'\");\n \n // \u5728\u63d0\u4ea4\u524d\uff0c\u5176\u4ed6\u4e8b\u52a1\u5e94\u8be5\u770b\u4e0d\u5230\u8fd9\u4e2a\u66f4\u65b0\n // \u8fd9\u91cc\u6211\u4eec\u53ea\u662f\u9a8c\u8bc1\u5f53\u524d\u4e8b\u52a1\u53ef\u4ee5\u770b\u5230\u66f4\u65b0\n try (ResultSet rs = executeQuery(\"SELECT balance FROM accounts WHERE account_name = 'TestAccount'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBigDecimal(\"balance\").doubleValue()).isEqualTo(1500.00);\n }\n \n connection.commit();\n \n printSuccess(\"\u4e8b\u52a1\u9694\u79bb\u7ea7\u522b\u6d4b\u8bd5\u901a\u8fc7\");\n } finally {\n connection.setAutoCommit(true);\n }\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5BEGIN\u548cSTART TRANSACTION\")\n public void testBeginTransaction() throws SQLException {\n // \u4f7f\u7528BEGIN\u5f00\u59cb\u4e8b\u52a1\n executeUpdate(\"BEGIN\");\n \n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('BeginTest', 500.00)\");\n \n // \u56de\u6eda\n executeUpdate(\"ROLLBACK\");\n \n // \u9a8c\u8bc1\u6570\u636e\u5df2\u56de\u6eda\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(0);\n \n // \u4f7f\u7528START TRANSACTION\n executeUpdate(\"START TRANSACTION\");\n executeUpdate(\"INSERT INTO accounts (account_name, balance) VALUES ('StartTest', 600.00)\");\n executeUpdate(\"COMMIT\");\n \n // \u9a8c\u8bc1\u6570\u636e\u5df2\u63d0\u4ea4\n assertThat(getTableRowCount(ACCOUNTS_TABLE)).isEqualTo(1);\n \n printSuccess(\"BEGIN/START TRANSACTION\u6d4b\u8bd5\u901a\u8fc7\");\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":3,"type":0,"content":"继续创建更多测试类：
