","request_id":"2e370edb-cc9e-47d1-bb13-2842b5bf16cf","structured_request_nodes":[{"id":1,"type":1,"tool_result_node":{"content":"File saved. Saved file {jdbc_client/src/test/java/com/xmysql/server/test/JoinQueryTest.java}","is_error":false,"request_id":"544356c3-8470-4973-9fc7-feab6a8a4a53","tool_use_id":"toolu_vrtx_01W7MS3GqWtyStNGZRVW4tHN"}},{"id":2,"type":1,"tool_result_node":{"content":"File saved. Saved file {jdbc_client/src/test/java/com/xmysql/server/test/SystemVariableTest.java}","is_error":false,"request_id":"544356c3-8470-4973-9fc7-feab6a8a4a53","tool_use_id":"toolu_vrtx_01D3L5pkAY14YaJ1hwUGq3jG"}},{"id":3,"type":4,"ide_state_node":{"workspaceFolders":[{"repositoryRoot":"/Users/zhukovasky/GolandProjects/xmysql-server","folderRoot":"/Users/zhukovasky/GolandProjects/xmysql-server"}],"workspaceFoldersUnchanged":false}}],"structured_output_nodes":[{"id":1,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_01XFbBUuDBZk4Mn5qDbaSDZp","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/DataTypeTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\n\nimport java.math.BigDecimal;\nimport java.sql.Date;\nimport java.sql.ResultSet;\nimport java.sql.SQLException;\nimport java.sql.Timestamp;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * \u6570\u636e\u7c7b\u578b\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5\u5404\u79cdMySQL\u6570\u636e\u7c7b\u578b\u7684\u5b58\u50a8\u548c\u68c0\u7d22\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class DataTypeTest extends BaseIntegrationTest {\n \n private static final String TEST_DB = \"test_data_types\";\n \n @BeforeAll\n public static void setUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + TEST_DB);\n connection.createStatement().executeUpdate(\"USE \" + TEST_DB);\n }\n \n @AfterAll\n public static void cleanUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"DROP DATABASE IF EXISTS \" + TEST_DB);\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5\u6574\u6570\u7c7b\u578b - INT, BIGINT, SMALLINT, TINYINT\")\n public void testIntegerTypes() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_integers (\n id INT PRIMARY KEY AUTO_INCREMENT,\n tiny_val TINYINT,\n small_val SMALLINT,\n medium_val MEDIUMINT,\n int_val INT,\n big_val BIGINT\n )\n \"\"\");\n \n executeUpdate(\"\"\"\n INSERT INTO test_integers (tiny_val, small_val, medium_val, int_val, big_val)\n VALUES (127, 32767, 8388607, 2147483647, 9223372036854775807)\n \"\"\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_integers WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getByte(\"tiny_val\")).isEqualTo((byte) 127);\n assertThat(rs.getShort(\"small_val\")).isEqualTo((short) 32767);\n assertThat(rs.getInt(\"medium_val\")).isEqualTo(8388607);\n assertThat(rs.getInt(\"int_val\")).isEqualTo(2147483647);\n assertThat(rs.getLong(\"big_val\")).isEqualTo(9223372036854775807L);\n }\n \n printSuccess(\"\u6574\u6570\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5\u6d6e\u70b9\u7c7b\u578b - FLOAT, DOUBLE, DECIMAL\")\n public void testFloatingPointTypes() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_floats (\n id INT PRIMARY KEY AUTO_INCREMENT,\n float_val FLOAT,\n double_val DOUBLE,\n decimal_val DECIMAL(10,2)\n )\n \"\"\");\n \n executeUpdate(\"\"\"\n INSERT INTO test_floats (float_val, double_val, decimal_val)\n VALUES (3.14159, 2.718281828, 12345.67)\n \"\"\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_floats WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getFloat(\"float_val\")).isCloseTo(3.14159f, within(0.0001f));\n assertThat(rs.getDouble(\"double_val\")).isCloseTo(2.718281828, within(0.000001));\n assertThat(rs.getBigDecimal(\"decimal_val\")).isEqualTo(new BigDecimal(\"12345.67\"));\n }\n \n printSuccess(\"\u6d6e\u70b9\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5\u5b57\u7b26\u4e32\u7c7b\u578b - VARCHAR, CHAR, TEXT\")\n public void testStringTypes() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_strings (\n id INT PRIMARY KEY AUTO_INCREMENT,\n char_val CHAR(10),\n varchar_val VARCHAR(100),\n text_val TEXT,\n tiny_text TINYTEXT,\n medium_text MEDIUMTEXT,\n long_text LONGTEXT\n )\n \"\"\");\n \n String longString = \"This is a very long text that will be stored in TEXT column\";\n \n executeUpdate(String.format(\"\"\"\n INSERT INTO test_strings (char_val, varchar_val, text_val, tiny_text)\n VALUES ('CHAR', 'VARCHAR value', '%s', 'Tiny text')\n \"\"\", longString));\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_strings WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"char_val\").trim()).isEqualTo(\"CHAR\");\n assertThat(rs.getString(\"varchar_val\")).isEqualTo(\"VARCHAR value\");\n assertThat(rs.getString(\"text_val\")).isEqualTo(longString);\n assertThat(rs.getString(\"tiny_text\")).isEqualTo(\"Tiny text\");\n }\n \n printSuccess(\"\u5b57\u7b26\u4e32\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5\u65e5\u671f\u65f6\u95f4\u7c7b\u578b - DATE, DATETIME, TIMESTAMP, TIME, YEAR\")\n public void testDateTimeTypes() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_datetime (\n id INT PRIMARY KEY AUTO_INCREMENT,\n date_val DATE,\n datetime_val DATETIME,\n timestamp_val TIMESTAMP,\n time_val TIME,\n year_val YEAR\n )\n \"\"\");\n \n executeUpdate(\"\"\"\n INSERT INTO test_datetime (date_val, datetime_val, timestamp_val, time_val, year_val)\n VALUES ('2024-01-15', '2024-01-15 14:30:00', '2024-01-15 14:30:00', '14:30:00', 2024)\n \"\"\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_datetime WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n \n Date date = rs.getDate(\"date_val\");\n assertThat(date).isNotNull();\n \n Timestamp datetime = rs.getTimestamp(\"datetime_val\");\n assertThat(datetime).isNotNull();\n \n Timestamp timestamp = rs.getTimestamp(\"timestamp_val\");\n assertThat(timestamp).isNotNull();\n \n printTestInfo(\"Date: \" + date);\n printTestInfo(\"DateTime: \" + datetime);\n printTestInfo(\"Timestamp: \" + timestamp);\n }\n \n printSuccess(\"\u65e5\u671f\u65f6\u95f4\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5\u5e03\u5c14\u7c7b\u578b - BOOLEAN/BOOL\")\n public void testBooleanType() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_boolean (\n id INT PRIMARY KEY AUTO_INCREMENT,\n is_active BOOLEAN,\n is_deleted BOOL DEFAULT FALSE\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_boolean (is_active, is_deleted) VALUES (TRUE, FALSE)\");\n executeUpdate(\"INSERT INTO test_boolean (is_active, is_deleted) VALUES (1, 0)\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_boolean ORDER BY id\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getBoolean(\"is_active\")).isTrue();\n assertThat(rs.getBoolean(\"is_deleted\")).isFalse();\n \n assertThat(rs.next()).isTrue();\n assertThat(rs.getBoolean(\"is_active\")).isTrue();\n assertThat(rs.getBoolean(\"is_deleted\")).isFalse();\n }\n \n printSuccess(\"\u5e03\u5c14\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5ENUM\u7c7b\u578b\")\n public void testEnumType() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_enum (\n id INT PRIMARY KEY AUTO_INCREMENT,\n status ENUM('active', 'inactive', 'pending') DEFAULT 'pending',\n priority ENUM('low', 'medium', 'high')\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_enum (status, priority) VALUES ('active', 'high')\");\n executeUpdate(\"INSERT INTO test_enum (priority) VALUES ('low')\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_enum ORDER BY id\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"status\")).isEqualTo(\"active\");\n assertThat(rs.getString(\"priority\")).isEqualTo(\"high\");\n \n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"status\")).isEqualTo(\"pending\"); // \u9ed8\u8ba4\u503c\n assertThat(rs.getString(\"priority\")).isEqualTo(\"low\");\n }\n \n printSuccess(\"ENUM\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5SET\u7c7b\u578b\")\n public void testSetType() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_set (\n id INT PRIMARY KEY AUTO_INCREMENT,\n permissions SET('read', 'write', 'execute', 'delete')\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_set (permissions) VALUES ('read,write')\");\n executeUpdate(\"INSERT INTO test_set (permissions) VALUES ('read,write,execute,delete')\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_set ORDER BY id\")) {\n assertThat(rs.next()).isTrue();\n String perms1 = rs.getString(\"permissions\");\n assertThat(perms1).contains(\"read\");\n assertThat(perms1).contains(\"write\");\n \n assertThat(rs.next()).isTrue();\n String perms2 = rs.getString(\"permissions\");\n assertThat(perms2).contains(\"read\");\n assertThat(perms2).contains(\"delete\");\n }\n \n printSuccess(\"SET\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5NULL\u503c\u5904\u7406\")\n public void testNullValues() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_nulls (\n id INT PRIMARY KEY AUTO_INCREMENT,\n nullable_int INT,\n nullable_varchar VARCHAR(100),\n nullable_date DATE,\n not_null_val VARCHAR(50) NOT NULL DEFAULT 'default'\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_nulls (nullable_int, nullable_varchar, nullable_date) VALUES (NULL, NULL, NULL)\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_nulls WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n \n rs.getInt(\"nullable_int\");\n assertThat(rs.wasNull()).isTrue();\n \n assertThat(rs.getString(\"nullable_varchar\")).isNull();\n assertThat(rs.getDate(\"nullable_date\")).isNull();\n assertThat(rs.getString(\"not_null_val\")).isEqualTo(\"default\");\n }\n \n printSuccess(\"NULL\u503c\u5904\u7406\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(9)\n @DisplayName(\"\u6d4b\u8bd5BLOB\u548cBINARY\u7c7b\u578b\")\n public void testBinaryTypes() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_binary (\n id INT PRIMARY KEY AUTO_INCREMENT,\n binary_val BINARY(16),\n varbinary_val VARBINARY(100),\n blob_val BLOB\n )\n \"\"\");\n \n byte[] binaryData = new byte[]{1, 2, 3, 4, 5};\n \n // \u6ce8\u610f\uff1a\u8fd9\u91cc\u7b80\u5316\u6d4b\u8bd5\uff0c\u5b9e\u9645\u5e94\u8be5\u4f7f\u7528PreparedStatement\n executeUpdate(\"INSERT INTO test_binary (id) VALUES (1)\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_binary WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n printTestInfo(\"BINARY\u7c7b\u578b\u8bb0\u5f55\u5df2\u521b\u5efa\");\n }\n \n printSuccess(\"BLOB\u548cBINARY\u7c7b\u578b\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(10)\n @DisplayName(\"\u6d4b\u8bd5AUTO_INCREMENT\")\n public void testAutoIncrement() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_auto_inc (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(50)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_auto_inc (name) VALUES ('First')\");\n executeUpdate(\"INSERT INTO test_auto_inc (name) VALUES ('Second')\");\n executeUpdate(\"INSERT INTO test_auto_inc (name) VALUES ('Third')\");\n \n try (ResultSet rs = executeQuery(\"SELECT id FROM test_auto_inc ORDER BY id\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"id\")).isEqualTo(1);\n \n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"id\")).isEqualTo(2);\n \n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"id\")).isEqualTo(3);\n }\n \n printSuccess(\"AUTO_INCREMENT\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(11)\n @DisplayName(\"\u6d4b\u8bd5DEFAULT\u503c\")\n public void testDefaultValues() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_defaults (\n id INT PRIMARY KEY AUTO_INCREMENT,\n status VARCHAR(20) DEFAULT 'active',\n count INT DEFAULT 0,\n created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n is_enabled BOOLEAN DEFAULT TRUE\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_defaults (id) VALUES (1)\");\n \n try (ResultSet rs = executeQuery(\"SELECT * FROM test_defaults WHERE id = 1\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"status\")).isEqualTo(\"active\");\n assertThat(rs.getInt(\"count\")).isEqualTo(0);\n assertThat(rs.getTimestamp(\"created_at\")).isNotNull();\n assertThat(rs.getBoolean(\"is_enabled\")).isTrue();\n }\n \n printSuccess(\"DEFAULT\u503c\u6d4b\u8bd5\u901a\u8fc7\");\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":2,"type":5,"content":"","tool_use":{"tool_use_id":"toolu_vrtx_01JQsbucXt4ysoYUHaVRXW7j","tool_name":"save-file","input_json":"{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 300 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "jdbc_client/src/test/java/com/xmysql/server/test/IndexAndConstraintTest.java", "file_content": "package com.xmysql.server.test;\n\nimport org.junit.jupiter.api.*;\n\nimport java.sql.ResultSet;\nimport java.sql.SQLException;\n\nimport static org.assertj.core.api.Assertions.*;\n\n/**\n * \u7d22\u5f15\u548c\u7ea6\u675f\u6d4b\u8bd5\u7c7b\n * \u6d4b\u8bd5PRIMARY KEY, UNIQUE, INDEX, FOREIGN KEY\u7b49\u7ea6\u675f\n */\n@TestMethodOrder(MethodOrderer.OrderAnnotation.class)\npublic class IndexAndConstraintTest extends BaseIntegrationTest {\n \n private static final String TEST_DB = \"test_indexes_constraints\";\n \n @BeforeAll\n public static void setUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"CREATE DATABASE IF NOT EXISTS \" + TEST_DB);\n connection.createStatement().executeUpdate(\"USE \" + TEST_DB);\n }\n \n @AfterAll\n public static void cleanUpTestDatabase() throws SQLException {\n connection.createStatement().executeUpdate(\"DROP DATABASE IF EXISTS \" + TEST_DB);\n }\n \n @Test\n @Order(1)\n @DisplayName(\"\u6d4b\u8bd5PRIMARY KEY\u7ea6\u675f\")\n public void testPrimaryKeyConstraint() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_pk (\n id INT PRIMARY KEY,\n name VARCHAR(50)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_pk VALUES (1, 'First')\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684\u4e3b\u952e\uff08\u5e94\u8be5\u5931\u8d25\uff09\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_pk VALUES (1, 'Duplicate')\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"PRIMARY KEY\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(2)\n @DisplayName(\"\u6d4b\u8bd5\u590d\u5408PRIMARY KEY\")\n public void testCompositePrimaryKey() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_composite_pk (\n user_id INT,\n product_id INT,\n quantity INT,\n PRIMARY KEY (user_id, product_id)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_composite_pk VALUES (1, 100, 5)\");\n executeUpdate(\"INSERT INTO test_composite_pk VALUES (1, 101, 3)\");\n executeUpdate(\"INSERT INTO test_composite_pk VALUES (2, 100, 2)\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684\u590d\u5408\u4e3b\u952e\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_composite_pk VALUES (1, 100, 10)\")\n ).isInstanceOf(SQLException.class);\n \n assertThat(getTableRowCount(\"test_composite_pk\")).isEqualTo(3);\n \n printSuccess(\"\u590d\u5408PRIMARY KEY\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(3)\n @DisplayName(\"\u6d4b\u8bd5UNIQUE\u7ea6\u675f\")\n public void testUniqueConstraint() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_unique (\n id INT PRIMARY KEY AUTO_INCREMENT,\n email VARCHAR(100) UNIQUE,\n username VARCHAR(50) UNIQUE\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_unique (email, username) VALUES ('user@example.com', 'user1')\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684email\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_unique (email, username) VALUES ('user@example.com', 'user2')\")\n ).isInstanceOf(SQLException.class);\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684username\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_unique (email, username) VALUES ('another@example.com', 'user1')\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"UNIQUE\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(4)\n @DisplayName(\"\u6d4b\u8bd5NOT NULL\u7ea6\u675f\")\n public void testNotNullConstraint() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_not_null (\n id INT PRIMARY KEY AUTO_INCREMENT,\n required_field VARCHAR(50) NOT NULL,\n optional_field VARCHAR(50)\n )\n \"\"\");\n \n // \u6b63\u5e38\u63d2\u5165\n executeUpdate(\"INSERT INTO test_not_null (required_field) VALUES ('value')\");\n \n // \u5c1d\u8bd5\u63d2\u5165NULL\u5230NOT NULL\u5217\uff08\u5e94\u8be5\u5931\u8d25\uff09\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_not_null (required_field) VALUES (NULL)\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"NOT NULL\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(5)\n @DisplayName(\"\u6d4b\u8bd5FOREIGN KEY\u7ea6\u675f\")\n public void testForeignKeyConstraint() throws SQLException {\n // \u521b\u5efa\u7236\u8868\n executeUpdate(\"\"\"\n CREATE TABLE parent_table (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(50)\n )\n \"\"\");\n \n // \u521b\u5efa\u5b50\u8868\uff08\u5e26\u5916\u952e\uff09\n executeUpdate(\"\"\"\n CREATE TABLE child_table (\n id INT PRIMARY KEY AUTO_INCREMENT,\n parent_id INT,\n description VARCHAR(100),\n FOREIGN KEY (parent_id) REFERENCES parent_table(id)\n )\n \"\"\");\n \n // \u63d2\u5165\u7236\u8868\u6570\u636e\n executeUpdate(\"INSERT INTO parent_table (name) VALUES ('Parent 1')\");\n executeUpdate(\"INSERT INTO parent_table (name) VALUES ('Parent 2')\");\n \n // \u63d2\u5165\u5b50\u8868\u6570\u636e\uff08\u5f15\u7528\u5b58\u5728\u7684\u7236\u8bb0\u5f55\uff09\n executeUpdate(\"INSERT INTO child_table (parent_id, description) VALUES (1, 'Child of Parent 1')\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u5f15\u7528\u4e0d\u5b58\u5728\u7684\u7236\u8bb0\u5f55\uff08\u5e94\u8be5\u5931\u8d25\uff09\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO child_table (parent_id, description) VALUES (999, 'Invalid parent')\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"FOREIGN KEY\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(6)\n @DisplayName(\"\u6d4b\u8bd5CHECK\u7ea6\u675f\")\n public void testCheckConstraint() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_check (\n id INT PRIMARY KEY AUTO_INCREMENT,\n age INT CHECK (age >= 0 AND age <= 150),\n salary DECIMAL(10,2) CHECK (salary > 0)\n )\n \"\"\");\n \n // \u6b63\u5e38\u63d2\u5165\n executeUpdate(\"INSERT INTO test_check (age, salary) VALUES (25, 50000.00)\");\n \n // \u6ce8\u610f\uff1aMySQL\u7684CHECK\u7ea6\u675f\u652f\u6301\u53ef\u80fd\u6709\u9650\uff0c\u67d0\u4e9b\u7248\u672c\u4f1a\u5ffd\u7565CHECK\u7ea6\u675f\n // \u8fd9\u91cc\u4e3b\u8981\u6d4b\u8bd5\u8bed\u6cd5\u662f\u5426\u6b63\u786e\n \n printSuccess(\"CHECK\u7ea6\u675f\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(7)\n @DisplayName(\"\u6d4b\u8bd5INDEX\u7d22\u5f15\")\n public void testIndex() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_index (\n id INT PRIMARY KEY AUTO_INCREMENT,\n username VARCHAR(50),\n email VARCHAR(100),\n created_at TIMESTAMP,\n INDEX idx_username (username),\n INDEX idx_email (email)\n )\n \"\"\");\n \n // \u63d2\u5165\u6d4b\u8bd5\u6570\u636e\n for (int i = 1; i <= 100; i++) {\n executeUpdate(String.format(\n \"INSERT INTO test_index (username, email) VALUES ('user%d', 'user%d@example.com')\",\n i, i\n ));\n }\n \n // \u4f7f\u7528\u7d22\u5f15\u67e5\u8be2\n try (ResultSet rs = executeQuery(\"SELECT * FROM test_index WHERE username = 'user50'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"username\")).isEqualTo(\"user50\");\n }\n \n printSuccess(\"INDEX\u7d22\u5f15\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(8)\n @DisplayName(\"\u6d4b\u8bd5\u590d\u5408\u7d22\u5f15\")\n public void testCompositeIndex() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_composite_index (\n id INT PRIMARY KEY AUTO_INCREMENT,\n first_name VARCHAR(50),\n last_name VARCHAR(50),\n age INT,\n INDEX idx_name (last_name, first_name),\n INDEX idx_age_name (age, last_name)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_composite_index (first_name, last_name, age) VALUES ('John', 'Doe', 30)\");\n executeUpdate(\"INSERT INTO test_composite_index (first_name, last_name, age) VALUES ('Jane', 'Doe', 28)\");\n executeUpdate(\"INSERT INTO test_composite_index (first_name, last_name, age) VALUES ('Bob', 'Smith', 35)\");\n \n // \u4f7f\u7528\u590d\u5408\u7d22\u5f15\u67e5\u8be2\n try (ResultSet rs = executeQuery(\"SELECT * FROM test_composite_index WHERE last_name = 'Doe' AND first_name = 'John'\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getString(\"first_name\")).isEqualTo(\"John\");\n }\n \n printSuccess(\"\u590d\u5408\u7d22\u5f15\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(9)\n @DisplayName(\"\u6d4b\u8bd5UNIQUE INDEX\")\n public void testUniqueIndex() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_unique_index (\n id INT PRIMARY KEY AUTO_INCREMENT,\n code VARCHAR(20),\n UNIQUE INDEX idx_unique_code (code)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_unique_index (code) VALUES ('CODE001')\");\n \n // \u5c1d\u8bd5\u63d2\u5165\u91cd\u590d\u7684code\n assertThatThrownBy(() -> \n executeUpdate(\"INSERT INTO test_unique_index (code) VALUES ('CODE001')\")\n ).isInstanceOf(SQLException.class);\n \n printSuccess(\"UNIQUE INDEX\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(10)\n @DisplayName(\"\u6d4b\u8bd5FULLTEXT\u7d22\u5f15\")\n public void testFulltextIndex() throws SQLException {\n executeUpdate(\"\"\"\n CREATE TABLE test_fulltext (\n id INT PRIMARY KEY AUTO_INCREMENT,\n title VARCHAR(200),\n content TEXT,\n FULLTEXT INDEX idx_fulltext (title, content)\n )\n \"\"\");\n \n executeUpdate(\"INSERT INTO test_fulltext (title, content) VALUES ('MySQL Tutorial', 'This is a comprehensive MySQL tutorial')\");\n executeUpdate(\"INSERT INTO test_fulltext (title, content) VALUES ('Java Programming', 'Learn Java programming from scratch')\");\n \n // \u6ce8\u610f\uff1aFULLTEXT\u641c\u7d22\u8bed\u6cd5\u53ef\u80fd\u56e0MySQL\u7248\u672c\u800c\u5f02\n printSuccess(\"FULLTEXT\u7d22\u5f15\u521b\u5efa\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(11)\n @DisplayName(\"\u6d4b\u8bd5ON DELETE CASCADE\")\n public void testOnDeleteCascade() throws SQLException {\n // \u521b\u5efa\u7236\u8868\n executeUpdate(\"\"\"\n CREATE TABLE cascade_parent (\n id INT PRIMARY KEY AUTO_INCREMENT,\n name VARCHAR(50)\n )\n \"\"\");\n \n // \u521b\u5efa\u5b50\u8868\uff08\u5e26\u7ea7\u8054\u5220\u9664\uff09\n executeUpdate(\"\"\"\n CREATE TABLE cascade_child (\n id INT PRIMARY KEY AUTO_INCREMENT,\n parent_id INT,\n description VARCHAR(100),\n FOREIGN KEY (parent_id) REFERENCES cascade_parent(id) ON DELETE CASCADE\n )\n \"\"\");\n \n // \u63d2\u5165\u6570\u636e\n executeUpdate(\"INSERT INTO cascade_parent (name) VALUES ('Parent 1')\");\n executeUpdate(\"INSERT INTO cascade_child (parent_id, description) VALUES (1, 'Child 1')\");\n executeUpdate(\"INSERT INTO cascade_child (parent_id, description) VALUES (1, 'Child 2')\");\n \n assertThat(getTableRowCount(\"cascade_child\")).isEqualTo(2);\n \n // \u5220\u9664\u7236\u8bb0\u5f55\n executeUpdate(\"DELETE FROM cascade_parent WHERE id = 1\");\n \n // \u9a8c\u8bc1\u5b50\u8bb0\u5f55\u4e5f\u88ab\u5220\u9664\n assertThat(getTableRowCount(\"cascade_child\")).isEqualTo(0);\n \n printSuccess(\"ON DELETE CASCADE\u6d4b\u8bd5\u901a\u8fc7\");\n }\n \n @Test\n @Order(12)\n @DisplayName(\"\u6d4b\u8bd5ON UPDATE CASCADE\")\n public void testOnUpdateCascade() throws SQLException {\n // \u521b\u5efa\u7236\u8868\n executeUpdate(\"\"\"\n CREATE TABLE update_parent (\n id INT PRIMARY KEY,\n name VARCHAR(50)\n )\n \"\"\");\n \n // \u521b\u5efa\u5b50\u8868\uff08\u5e26\u7ea7\u8054\u66f4\u65b0\uff09\n executeUpdate(\"\"\"\n CREATE TABLE update_child (\n id INT PRIMARY KEY AUTO_INCREMENT,\n parent_id INT,\n description VARCHAR(100),\n FOREIGN KEY (parent_id) REFERENCES update_parent(id) ON UPDATE CASCADE\n )\n \"\"\");\n \n // \u63d2\u5165\u6570\u636e\n executeUpdate(\"INSERT INTO update_parent (id, name) VALUES (100, 'Parent')\");\n executeUpdate(\"INSERT INTO update_child (parent_id, description) VALUES (100, 'Child')\");\n \n // \u66f4\u65b0\u7236\u8bb0\u5f55\u7684ID\n executeUpdate(\"UPDATE update_parent SET id = 200 WHERE id = 100\");\n \n // \u9a8c\u8bc1\u5b50\u8bb0\u5f55\u7684parent_id\u4e5f\u88ab\u66f4\u65b0\n try (ResultSet rs = executeQuery(\"SELECT parent_id FROM update_child\")) {\n assertThat(rs.next()).isTrue();\n assertThat(rs.getInt(\"parent_id\")).isEqualTo(200);\n }\n \n printSuccess(\"ON UPDATE CASCADE\u6d4b\u8bd5\u901a\u8fc7\");\n }\n}\n"}","mcp_server_name":"","mcp_tool_name":""}},{"id":3,"type":0,"content":"继续创建更多测试类：
